using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string Text { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    Models.SummarizeResponse Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

/// <summary>
/// Produces an extractive summary by scoring sentences based on word frequency
/// and returning the top-ranked sentences in their original order.
/// </summary>
public partial class ExtractiveSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been","being",
        "have","has","had","do","does","did","will","would","could","should","may",
        "might","shall","can","need","dare","ought","used","to","of","in","for","on",
        "with","at","by","from","as","into","through","during","before","after",
        "above","below","between","out","off","over","under","again","further","then",
        "once","here","there","when","where","why","how","all","each","every","both",
        "few","more","most","other","some","such","no","nor","not","only","own","same",
        "so","than","too","very","just","because","if","while","about","up","it","its",
        "this","that","these","those","i","me","my","we","our","you","your","he","him",
        "his","she","her","they","them","their","what","which","who","whom"
    };

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"[^\w\s]")]
    private static partial Regex PunctuationStripper();

    public SummarizeResponse Summarize(string text, int maxSentences)
    {
        var sentences = SentenceSplitter()
            .Split(text.Trim())
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToList();

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        // Build word frequency map (excluding stop words)
        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word))
                    wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
            }
        }

        // Score each sentence by the sum of its word frequencies
        var scored = sentences
            .Select((sentence, index) => new
            {
                Sentence = sentence,
                Index = index,
                Score = Tokenize(sentence)
                    .Where(w => !StopWords.Contains(w))
                    .Sum(w => wordFrequency.GetValueOrDefault(w))
            })
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        var summary = string.Join(" ", scored);

        return new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = maxSentences
        };
    }

    private static IEnumerable<string> Tokenize(string sentence)
    {
        var cleaned = PunctuationStripper().Replace(sentence, "");
        return cleaned.Split(' ', StringSplitOptions.RemoveEmptyEntries);
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummaryController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var result = _summaryService.Summarize(request.Text, request.MaxSentences);
        return Ok(result);
    }
}

